import json,sys
g=json.load(sys.stdin)

# Print all layers with their nodeIds
print('=== ARCHITECTURE LAYERS ===')
for layer in g.get('layers',[]):
    print(f\"\n{layer['id']} - {layer['name']}\")
    print(f\"  Description: {layer.get('description','')}\")
    print(f\"  Nodes ({len(layer.get('nodeIds',[]))}):\")
    for nid in layer.get('nodeIds',[]):
        print(f\"    - {nid}\")

print('\n=== EDGE TYPES ===')
edge_types = {}
for e in g.get('edges',[]):
    t = e.get('type','unknown')
    edge_types[t] = edge_types.get(t,0) + 1
for t,c in sorted(edge_types.items(), key=lambda x:-x[1]):
    print(f\"  {t}: {c}\")

print('\n=== NODE TYPES ===')
node_types = {}
for n in g.get('nodes',[]):
    t = n.get('type','unknown')
    node_types[t] = node_types.get(t,0) + 1
for t,c in sorted(node_types.items(), key=lambda x:-x[1]):
    print(f\"  {t}: {c}\")
"

