import json,sys
g=json.load(sys.stdin)

# Find pattern-related tags
print('=== DESIGN PATTERNS IDENTIFIED ===')
patterns = {}
for n in g.get('nodes',[]):
    for tag in n.get('tags',[]):
        if any(p in tag.lower() for p in ['singleton','factory','builder','strategy','observer','bridge','adapter','proxy','facade']):
            patterns[tag] = patterns.get(tag,0) + 1

for p,c in sorted(patterns.items(), key=lambda x:-x[1]):
    print(f'  {p}: {c}')

print('\n=== KEY CLASSES AND FUNCTIONS ===')
for n in g.get('nodes',[]):
    if n.get('type') in ['class','function'] and n.get('complexity') == 'complex':
        print(f\"  {n['id']}\")
        print(f\"    Summary: {n.get('summary','')[:100]}...\")
